    multi_asset = True

    def __init__(self, params=None):
        cfg = {
            'rebal': 21,
            'mom_lb': 252,
            'sma_lb': 200,
            'n_top': 3,
            'vol_lb': 21,
            'max_alloc': 0.95,
            'vix_crash': 35,
        }
