    def _mom(self, series, bar):
        lb = self.params['mom_lb']
        if bar < lb:
            return None
        p0 = float(series.iloc[bar])
        p_lb = float(series.iloc[bar - lb])
        if p_lb <= 0:
            return None
        return p0 / p_lb - 1.0

    def _above_sma(self, series, bar):
        lb = self.params['sma_lb']
        if bar < lb:
            return False
        price = float(series.iloc[bar])
        sma = float(series.iloc[bar - lb:bar].mean())
        return price > sma

    def _vol(self, series, bar):
        lb = self.params['vol_lb']
        if bar < lb + 1:
            return 0.15
        rets = series.iloc[bar - lb:bar + 1].pct_change().dropna()
        if len(rets) < 5:
            return 0.15
        return max(float(rets.std() * np.sqrt(252)), 0.01)

